--[[\n    Drawing API Utility - Wrapper for Drawing library functionality\n]]\n\nlocal Drawing = {}\n\nfunction Drawing.createLine(from, to, color, thickness, transparency)\n    if not Drawing.new then\n        return nil\n    end\n    \n    local line = Drawing.new(\"Line\")\n    line.From = from\n    line.To = to\n    line.Color = color or Color3.fromRGB(255, 255, 255)\n    line.Thickness = thickness or 1\n    line.Transparency = transparency or 1\n    line.Visible = true\n    \n    return line\nend\n\nfunction Drawing.createCircle(position, radius, color, thickness, transparency)\n    if not Drawing.new then\n        return nil\n    end\n    \n    local circle = Drawing.new(\"Circle\")\n    circle.Position = position\n    circle.Radius = radius or 50\n    circle.Color = color or Color3.fromRGB(255, 255, 255)\n    circle.Thickness = thickness or 2\n    circle.Transparency = transparency or 1\n    circle.Visible = true\n    circle.Filled = false\n    \n    return circle\nend\n\nfunction Drawing.createFilledCircle(position, radius, color, transparency)\n    if not Drawing.new then\n        return nil\n    end\n    \n    local circle = Drawing.new(\"Circle\")\n    circle.Position = position\n    circle.Radius = radius or 50\n    circle.Color = color or Color3.fromRGB(255, 255, 255)\n    circle.Transparency = transparency or 1\n    circle.Visible = true\n    circle.Filled = true\n    \n    return circle\nend\n\nfunction Drawing.createRectangle(position, size, color, thickness, transparency)\n    if not Drawing.new then\n        return nil\n    end\n    \n    local rect = Drawing.new(\"Square\")\n    rect.Position = position\n    rect.Size = size or Vector2.new(100, 100)\n    rect.Color = color or Color3.fromRGB(255, 255, 255)\n    rect.Thickness = thickness or 2\n    rect.Transparency = transparency or 1\n    rect.Visible = true\n    rect.Filled = false\n    \n    return rect\nend\n\nfunction Drawing.createFilledRectangle(position, size, color, transparency)\n    if not Drawing.new then\n        return nil\n    end\n    \n    local rect = Drawing.new(\"Square\")\n    rect.Position = position\n    rect.Size = size or Vector2.new(100, 100)\n    rect.Color = color or Color3.fromRGB(255, 255, 255)\n    rect.Transparency = transparency or 1\n    rect.Visible = true\n    rect.Filled = true\n    \n    return rect\nend\n\nfunction Drawing.createText(position, text, size, color, font, transparency)\n    if not Drawing.new then\n        return nil\n    end\n    \n    local textDraw = Drawing.new(\"Text\")\n    textDraw.Position = position\n    textDraw.Text = text or \"Text\"\n    textDraw.Size = size or 14\n    textDraw.Color = color or Color3.fromRGB(255, 255, 255)\n    textDraw.Font = font or 2\n    textDraw.Transparency = transparency or 1\n    textDraw.Visible = true\n    textDraw.Center = false\n    \n    return textDraw\nend\n\nfunction Drawing.createTriangle(a, b, c, color, thickness, transparency)\n    if not Drawing.new then\n        return nil\n    end\n    \n    local tri = Drawing.new(\"Triangle\")\n    tri.PointA = a\n    tri.PointB = b\n    tri.PointC = c\n    tri.Color = color or Color3.fromRGB(255, 255, 255)\n    tri.Thickness = thickness or 2\n    tri.Transparency = transparency or 1\n    tri.Visible = true\n    tri.Filled = false\n    \n    return tri\nend\n\nfunction Drawing.createFilledTriangle(a, b, c, color, transparency)\n    if not Drawing.new then\n        return nil\n    end\n    \n    local tri = Drawing.new(\"Triangle\")\n    tri.PointA = a\n    tri.PointB = b\n    tri.PointC = c\n    tri.Color = color or Color3.fromRGB(255, 255, 255)\n    tri.Transparency = transparency or 1\n    tri.Visible = true\n    tri.Filled = true\n    \n    return tri\nend\n\nfunction Drawing.clearAll()\n    if Drawing.new then\n        for _, obj in ipairs(Drawing.GetObjects()) do\n            pcall(function() obj:Remove() end)\n        end\n    end\nend\n\nreturn Drawing\n